use std::collections::HashSet;

/// Validates that each string in the provided vector is composed of non-whitespace,
/// non-repeated elements separated by single spaces.
///
/// # Examples
///
/// ```
/// assert_eq!(validate_strings(vec![String::from("hello world"), "  this", String::from("")]), Ok(()));
/// assert_eq!(validate_strings(vec![String::from(""), "  hello  "), Err(String::from("'hello' has two consecutive whitespaces."))),);
/// ```
fn validate_strings(vec: Vec<String>) -> Result<(), String> {
    let mut seen = HashSet::new();
    for item in vec.iter() {
        let trimmed = item.trim().to_string();
        if !trimmed.is_empty() && seen.contains(&trimmed) {
            return Err(format!("'{trimmed}' has two consecutive whitespaces."));
        }
        seen.insert(trimmed);
    }
    Ok(())
}

