    assert_eq!(validate_strings(vec![String::from("hello world"), "  this", String::from("")]), Ok(()));
    assert_eq!(validate_strings(vec![String::from(""), "  hello  "]), Err(String::from("'hello' has two consecutive whitespaces.")));
}
